import{_ as e,o as a,c as r,a2 as n}from"./chunks/framework.CQMe4Urg.js";const c=JSON.parse('{"title":"第 10 章 多 Agent 系统","description":"","frontmatter":{},"headers":[],"relativePath":"10-multi-agent/index.md","filePath":"10-multi-agent/index.md","lastUpdated":1776333512000}'),i={name:"10-multi-agent/index.md"};function l(o,t,d,g,h,s){return a(),r("div",null,[...t[0]||(t[0]=[n('<h1 id="第-10-章-多-agent-系统" tabindex="-1">第 10 章 多 Agent 系统 <a class="header-anchor" href="#第-10-章-多-agent-系统" aria-label="Permalink to &quot;第 10 章 多 Agent 系统&quot;">​</a></h1><p>当单个 Agent 遇到跨领域、多视角、大规模的任务时，它的局限性就暴露了：一个 prompt 很难同时扮演研究员、分析师和写手。<strong>多 Agent 系统</strong>的核心思路很直接——让专业的 Agent 做专业的事，然后把它们的成果协调整合起来。</p><p>这和现实世界的团队协作是一回事。你不会让一个人同时写代码、做测试、写文档，而是分工协作。多 Agent 系统就是把这种分工模式搬到了 AI 世界：每个 Agent 有自己的角色定义、专属工具和上下文，通过某种协调机制（监督者、消息总线、共享黑板）来完成复杂任务。</p><p>当然，多 Agent 不是越多越好。Agent 之间的通信有成本，协调有复杂度，分歧需要解决。这一章会帮你搞清楚：什么时候该用多 Agent，怎么选架构模式，以及如何处理 Agent 之间的通信、调度和冲突。</p><h2 id="本章内容" tabindex="-1">本章内容 <a class="header-anchor" href="#本章内容" aria-label="Permalink to &quot;本章内容&quot;">​</a></h2><table tabindex="0"><thead><tr><th>层级</th><th>内容</th><th>你将学到</th></tr></thead><tbody><tr><td><a href="./beginner.html">入门篇</a></td><td>为什么需要多 Agent、五种基本架构模式</td><td>各模式的适用场景，Supervisor 和 Pipeline 的完整实现</td></tr><tr><td><a href="./intermediate.html">进阶篇</a></td><td>Agent 间通信、任务分解与调度、冲突解决与共识</td><td>消息总线、黑板模式、事件驱动、依赖管理、投票和仲裁机制</td></tr><tr><td><a href="./advanced.html">高级篇</a></td><td>大规模编排、动态 Agent 生成、Agent 社会模拟</td><td>异步调度器、Agent 工厂、多 Agent 辩论与涌现行为</td></tr></tbody></table><h2 id="参考资源" tabindex="-1">参考资源 <a class="header-anchor" href="#参考资源" aria-label="Permalink to &quot;参考资源&quot;">​</a></h2><ul><li><a href="https://langchain-ai.github.io/langgraph/concepts/multi_agent/" target="_blank" rel="noreferrer">LangGraph: Multi-Agent Architectures</a> -- LangGraph 多 Agent 文档</li><li><a href="https://microsoft.github.io/autogen/" target="_blank" rel="noreferrer">AutoGen: Multi-Agent Conversation Framework</a> -- Microsoft 多 Agent 框架</li><li><a href="https://docs.crewai.com/" target="_blank" rel="noreferrer">CrewAI Documentation</a> -- CrewAI 多角色协作框架</li><li><a href="https://arxiv.org/abs/2308.00352" target="_blank" rel="noreferrer">MetaGPT (arXiv:2308.00352)</a> -- MetaGPT 多 Agent 论文</li><li><a href="https://www.youtube.com/watch?v=sal78ACtGTc" target="_blank" rel="noreferrer">Andrew Ng: Multi-Agent Systems</a> -- Andrew Ng 讲解多 Agent</li></ul>',8)])])}const p=e(i,[["render",l]]);export{c as __pageData,p as default};
